mapper.insert:
/* QueryID = insertBoard */
insert into board(title, content, author, created_at, updated_at)
VALUES (#{title}, #{content}, #{author}, now(), default)

mapper.select:
/* QueryID = selectAllBoard */
select seq, title, content, author, created_at
from board

/* QueryID = selectBoardBySeq */
select seq, title, content, author, created_at
from board
where seq = #{seq}
